#include <bits/stdc++.h>
using namespace std;


string s;
int t;
int main(){
	cin>>s>>t;
	while(t--){
		int k=s.size()-1;
		for(int i=0;i<s.size()-1;i++){
			if(s[i]>s[i+1]){
				k=i;
				break;
			}
		}
		s.erase(k,1);
	}
	int i=0;
	while(s[i]=='0'&&s.size()>1){
		s.erase(0,1);
	}
	if(s!="") cout<<s;
	else cout<<0;
	return 0;
}
